class Solution:
    def solve(self, strs: List[str]) -> str:
        if not strs: return ""
        res = ""
        strs.sort()
        first, last = strs[0], strs[-1]
        for i in range(min(len(first), len(last))):
            if first[i] != last[i]: return res
            res += first[i]
        return res

